// Dart is single-threaded per isolate, but the OS-level concepts are the same.
// This shows the DANGER of two threads/isolates sharing state.

import 'dart:isolate';

var counter = 0;                    // shared 'fridge'

void worker(SendPort _) {
  for (var i = 0; i < 100000; i++) {
    counter++;                      // NOT atomic — two isolates would collide
  }
}

void main() async {
  // If you naively spawn 4 workers all incrementing 'counter',
  // the final value is NOT 400,000 — some updates get lost.
  // That's a RACE CONDITION.
  // (In Dart, each isolate has its own memory, so this specific example
  //  is safe — but Java/Kotlin/C++ threads would race here.)
}

// Deadlock, illustrated as pseudo-code:
// Thread A                     Thread B
// -----------------            -----------------
// lock(X)                      lock(Y)
//   lock(Y)  <-- waits         lock(X)  <-- waits
//   ...                        ...
// unlock(Y)                    unlock(X)
// unlock(X)                    unlock(Y)
//
// Both wait for the lock the other is holding. Neither ever wakes up.
// Fix: EVERY thread must acquire X BEFORE Y. Enforce a single global order.

// File: RaceDemo.java
// Compile: javac RaceDemo.java
// Run:     java RaceDemo

import java.util.concurrent.atomic.AtomicInteger;

public class RaceDemo {
  static int broken = 0;
  static AtomicInteger fixed = new AtomicInteger(0);

  public static void main(String[] args) throws Exception {
    Thread[] ts = new Thread[10];
    for (int i = 0; i < 10; i++) {
      ts[i] = new Thread(() -> {
        for (int j = 0; j < 100000; j++) {
          broken++;             // RACE — some updates get lost
          fixed.incrementAndGet(); // ATOMIC — always correct
        }
      });
      ts[i].start();
    }
    for (Thread t : ts) t.join();

    System.out.println("broken (racy):    " + broken);
    System.out.println("fixed (atomic):   " + fixed.get());
    System.out.println("expected:         1000000");
  }
}

// Typical output on any laptop:
//   broken (racy):    734128     (varies EVERY run)
//   fixed (atomic):   1000000    (always correct)
//   expected:         1000000
//
// The broken counter is missing ~27% of updates. That's the race in action.
